@startuml
left to right direction
skinparam packageStyle rectangle
skinparam class {
  BackgroundColor White
  ArrowColor Black
  BorderColor Black
  FontColor Black
}

class CylinderBlock {
  [C] CylinderBlock
}

class Sump {
  [C] Sump
}

class Crankshaft {
  [C] Crankshaft
}

class Rod {
  [C] Rod
}

class Engine {
  [C] Engine
  Container: list.List
}

class CarPart {
  [I] CarPart
  PrintPart()
  AddPart(v interface{})
  RemovePart(v interface{})
}

class Absorber {
  [C] Absorber
}

class Damping {
  [C] Damping
}

class Stabilizer {
  [C] Stabilizer
}

class Rack {
  [C] Rack
}

class Lever {
  [C] Lever
}

class Spring {
  [C] Spring
}

class Suspenssion {
  [C] Suspenssion
  Container: list.List
}

class Car {
  [C] Car
  Container: list.List
}

CylinderBlock --> Engine
Sump --> Engine
Crankshaft --> Engine
Rod ..> CarPart
Rod ..> Engine
Engine --> Car
Absorber ..> CarPart
Absorber --> Suspenssion
Damping ..> CarPart
Damping --> Suspenssion
Stabilizer --> Suspenssion
Rack --> Suspenssion
Lever --> Suspenssion
Spring --> Suspenssion
CarPart ..> Car
@enduml
